import {GestureDetector, Gesture} from 'react-native-gesture-handler';
import Animated, {useSharedValue, useAnimatedStyle, withSpring} from 'react-native-reanimated';
const GRID = 80;
export function MagneticDrag({children}: {children: React.ReactNode}) { const x = useSharedValue(0); const y = useSharedValue(0); const pan = Gesture.Pan().onUpdate(e => { x.value = e.translationX; y.value = e.translationY; }).onEnd(() => { x.value = withSpring(Math.round(x.value / GRID) * GRID, {damping: 18}); y.value = withSpring(Math.round(y.value / GRID) * GRID, {damping: 18}); }); const style = useAnimatedStyle(() => ({transform: [{translateX: x.value}, {translateY: y.value}]})); return (<GestureDetector gesture={pan}><Animated.View style={style}>{children}</Animated.View></GestureDetector>); }

