export function InteractiveShader({ width, height }: { width: number; height: number }) {
  const x = useSharedValue(width / 2);
  const y = useSharedValue(height / 2);
  const pan = Gesture.Pan().onChange((e) => { x.value = e.x; y.value = e.y; });

  return (
