        <Fill>
          <RuntimeShader source={source} uniforms={{ pointer: [x, y] }} />
        </Fill>
      </Canvas>
    </GestureDetector>
  );
}

import React, { useEffect, useState } from 'react';
import { FlatList } from 'react-native';
import * as MediaLibrary from 'expo-media-library';

type AlbumGroup = { id: string; title: string; assetIds: string[] };

export function SmartAlbums({ faceProvider }: { faceProvider: (asset: MediaLibrary.Asset) => Promise<string[]> }) {
  const [groups, setGroups] = useState<AlbumGroup[]>([]);

  useEffect(() => {
    let cancelled = false;
    async function load() {
      const { status } = await MediaLibrary.requestPermissionsAsync();
      if (status !== 'granted') return;
      const page = await MediaLibrary.getAssetsAsync({ mediaType: 'photo', first: 500, sortBy: ['creationTime'] });
      const byPlace = groupByLocation(page.assets);
      const byFace = await groupByFace(page.assets, faceProvider);
      if (!cancelled) setGroups([...byFace, ...byPlace]);
    }
    load();
    return () => { cancelled = true; };
  }, [faceProvider]);

  return <FlatList data={groups} keyExtractor={(g) => g.id} renderItem={({ item }) => <AlbumTile title={item.title} count={item.assetIds.length} />} />;
}

