import React, { useMemo } from 'react';
import { Canvas, Path, Skia } from '@shopify/react-native-skia';
import { useFrameCallback, useSharedValue } from 'react-native-reanimated';
import { View } from 'react-native';

type Sample = { t: number; value: number };
type Series = { id: string; color: string; samples: Sample[] };

function buildPath(samples: Sample[], width: number, height: number) {
  const path = Skia.Path.Make();
  samples.slice(-300).forEach((p, index, windowed) => {
    const x = (index / Math.max(1, windowed.length - 1)) * width;
    const y = height - Math.max(0, Math.min(1, p.value)) * height;
    index === 0 ? path.moveTo(x, y) : path.lineTo(x, y);
  });
  return path;
}

export function MultiSeriesLive({ series, width, height }: { series: Series[]; width: number; height: number }) {
  const frame = useSharedValue(0);
  useFrameCallback(() => { frame.value += 1; });
  const paths = useMemo(() => series.map((s) => ({ id: s.id, color: s.color, path: buildPath(s.samples, width, height) })), [series, width, height, frame.value]);
  const summary = series.map((s) => `${s.id}: ${s.samples.at(-1)?.value ?? 0}`).join(', ');

  return (
    <View accessible accessibilityRole="image" accessibilityLabel={`Live chart. ${summary}`}>
      <Canvas style={{ width, height }}>
        {paths.map((s) => <Path key={s.id} path={s.path} color={s.color} style="stroke" strokeWidth={2} />)}
      </Canvas>
    </View>
  );
}

