import React, {useState, useCallback} from 'react';
export function useOptimisticToggle(initial: boolean, mutate: (v: boolean) => Promise<boolean>) { const [value, setValue] = useState(initial); const toggle = useCallback(async () => { const next = !value; setValue(next); try { await mutate(next); } catch { setValue(!next); }}, [value, mutate]); return [value, toggle] as const; }

import React from 'react';
import { Canvas, Circle } from '@shopify/react-native-skia';
import { Gesture, GestureDetector } from 'react-native-gesture-handler';
import { useFrameCallback, useSharedValue } from 'react-native-reanimated';

type Ball = { x: number; y: number; vx: number; vy: number; r: number; color: string };

export function PhysicsCanvas({ width, height }: { width: number; height: number }) {
  const balls = useSharedValue<Ball[]>([]);
  useFrameCallback((frame) => {
    const dt = Math.min((frame.timeSincePreviousFrame ?? 16) / 1000, 0.033);
    balls.value = stepPhysics(balls.value, dt, width, height).slice(0, 80);
  });
  const tap = Gesture.Tap().onEnd((e) => { balls.value = [...balls.value, makeBall(e.x, e.y)]; });

  return (
    <GestureDetector gesture={tap}>
      <Canvas style={{ width, height }} accessible accessibilityLabel={`${balls.value.length} bouncing balls`}>
        {balls.value.map((b, i) => <Circle key={i} cx={b.x} cy={b.y} r={b.r} color={b.color} />)}
      </Canvas>
    </GestureDetector>
  );
}

